#include <bits/stdc++.h>
using namespace std;

// Dijkstra 算法（优先队列优化）
vector<long long> dijkstra(int n, vector<vector<pair<int, int>>>& adj, int src) {
    vector<long long> dist(n, LLONG_MAX);
    dist[src] = 0;
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    pq.push({0, src});
    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();
        if (d > dist[u]) continue;
        for (auto [v, w] : adj[u]) {
            if (dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}

// Bellman-Ford 算法（检测负环）
bool bellmanFord(int n, vector<tuple<int, int, int>>& edges, int src, vector<long long>& dist) {
    dist.assign(n, LLONG_MAX);
    dist[src] = 0;
    for (int i = 0; i < n - 1; i++) {
        for (auto [u, v, w] : edges) {
            if (dist[u] != LLONG_MAX && dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
            }
        }
    }
    for (auto [u, v, w] : edges) {
        if (dist[u] != LLONG_MAX && dist[v] > dist[u] + w) {
            return true; // 存在负环
        }
    }
    return false;
}

// SPFA 算法（队列优化）
vector<long long> spfa(int n, vector<vector<pair<int, int>>>& adj, int src) {
    vector<long long> dist(n, LLONG_MAX);
    vector<bool> inQueue(n, false);
    queue<int> q;
    dist[src] = 0;
    q.push(src);
    inQueue[src] = true;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        inQueue[u] = false;
        for (auto [v, w] : adj[u]) {
            if (dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
                if (!inQueue[v]) {
                    q.push(v);
                    inQueue[v] = true;
                }
            }
        }
    }
    return dist;
}

// Floyd-Warshall 算法（全源最短路）
vector<vector<long long>> floydWarshall(int n, vector<vector<long long>>& dist) {
    for (int k = 0; k < n; k++) {
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (dist[i][k] != LLONG_MAX && dist[k][j] != LLONG_MAX) {
                    dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]);
                }
            }
        }
    }
    return dist;
}

#include <bits/stdc++.h>
using namespace std;

// Kruskal算法模板
struct Edge {
    int u, v, w;
    bool operator<(const Edge& other) const {
        return w < other.w;
    }
};

class DSU {
    vector<int> parent, rank;
public:
    DSU(int n) {
        parent.resize(n);
        rank.resize(n, 0);
        for (int i = 0; i < n; i++) parent[i] = i;
    }
    int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }
    bool unite(int x, int y) {
        x = find(x); y = find(y);
        if (x == y) return false;
        if (rank[x] < rank[y]) parent[x] = y;
        else if (rank[x] > rank[y]) parent[y] = x;
        else { parent[y] = x; rank[x]++; }
        return true;
    }
};

long long kruskal(int n, vector<Edge>& edges) {
    sort(edges.begin(), edges.end());
    DSU dsu(n);
    long long total = 0;
    int cnt = 0;
    for (auto& e : edges) {
        if (dsu.unite(e.u, e.v)) {
            total += e.w;
            cnt++;
            if (cnt == n - 1) break;
        }
    }
    return cnt == n - 1 ? total : -1; // 返回-1表示不连通
}

// Prim算法模板（邻接矩阵，稠密图）
long long prim_dense(int n, vector<vector<int>>& g) {
    vector<int> dist(n, INT_MAX);
    vector<bool> vis(n, false);
    dist[0] = 0;
    long long total = 0;
    for (int i = 0; i < n; i++) {
        int u = -1;
        for (int j = 0; j < n; j++) {
            if (!vis[j] && (u == -1 || dist[j] < dist[u])) u = j;
        }
        if (dist[u] == INT_MAX) return -1;
        vis[u] = true;
        total += dist[u];
        for (int v = 0; v < n; v++) {
            if (!vis[v] && g[u][v] < dist[v]) dist[v] = g[u][v];
        }
    }
    return total;
}

// Prim算法模板（邻接表+优先队列，稀疏图）
long long prim_sparse(int n, vector<vector<pair<int, int>>>& adj) {
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    vector<bool> vis(n, false);
    pq.push({0, 0});
    long long total = 0;
    int cnt = 0;
    while (!pq.empty() && cnt < n) {
        auto [w, u] = pq.top(); pq.pop();
        if (vis[u]) continue;
        vis[u] = true;
        total += w;
        cnt++;
        for (auto& [v, weight] : adj[u]) {
            if (!vis[v]) pq.push({weight, v});
        }
    }
    return cnt == n ? total : -1;
}

