// Tarjan求强连通分量
int dfn[N], low[N], timestamp;
int stk[N], top;
bool in_stk[N];
int scc_id[N], scc_cnt;

void tarjan(int u) {
    dfn[u] = low[u] = ++timestamp;
    stk[++top] = u;
    in_stk[u] = true;

    for (int v : g[u]) {
        if (!dfn[v]) {
            tarjan(v);
            low[u] = min(low[u], low[v]);
        } else if (in_stk[v]) {
            low[u] = min(low[u], dfn[v]);
        }
    }

    if (dfn[u] == low[u]) {
        ++scc_cnt;
        int y;
        do {
            y = stk[top--];
            in_stk[y] = false;
            scc_id[y] = scc_cnt;
        } while (y != u);
    }
}

// Tarjan求割点
bool cut[N];
int root;

void tarjan_cut(int u) {
    dfn[u] = low[u] = ++timestamp;
    int child = 0;

    for (int v : g[u]) {
        if (!dfn[v]) {
            tarjan_cut(v);
            low[u] = min(low[u], low[v]);

            if (low[v] >= dfn[u]) {
                child++;
                if (u != root || child > 1) cut[u] = true;
            }
        } else {
            low[u] = min(low[u], dfn[v]);
        }
    }
}

// Tarjan求桥
vector<pair<int, int>> bridges;

void tarjan_bridge(int u, int from) {
    dfn[u] = low[u] = ++timestamp;

    for (int v : g[u]) {
        if (v == from) continue;
        if (!dfn[v]) {
            tarjan_bridge(v, u);
            low[u] = min(low[u], low[v]);

            if (low[v] > dfn[u]) {
                bridges.push_back({u, v});
            }
        } else {
            low[u] = min(low[u], dfn[v]);
        }
    }
}

