#include <bits/stdc++.h>
using namespace std;

const int N = 2e5 + 5;
const int LOG = 20;
vector<int> adj[N];
int depth[N], parent[N][LOG];
int sz[N], heavy[N], head[N], pos[N], cur_pos;
int dp[N]; // 树形DP数组

// LCA预处理
void dfs_lca(int u, int p) {
    parent[u][0] = p;
    depth[u] = depth[p] + 1;
    for (int i = 1; i < LOG; i++) {
        parent[u][i] = parent[parent[u][i-1]][i-1];
    }
    for (int v : adj[u]) {
        if (v != p) dfs_lca(v, u);
    }
}

int lca(int u, int v) {
    if (depth[u] < depth[v]) swap(u, v);
    int diff = depth[u] - depth[v];
    for (int i = 0; i < LOG; i++) {
        if (diff & (1 << i)) u = parent[u][i];
    }
    if (u == v) return u;
    for (int i = LOG-1; i >= 0; i--) {
        if (parent[u][i] != parent[v][i]) {
            u = parent[u][i];
            v = parent[v][i];
        }
    }
    return parent[u][0];
}

// 树链剖分预处理
void dfs_hld(int u, int p) {
    sz[u] = 1;
    heavy[u] = -1;
    for (int v : adj[u]) {
        if (v == p) continue;
        dfs_hld(v, u);
        sz[u] += sz[v];
        if (heavy[u] == -1 || sz[v] > sz[heavy[u]]) {
            heavy[u] = v;
        }
    }
}

void decompose(int u, int h, int p) {
    head[u] = h;
    pos[u] = cur_pos++;
    if (heavy[u] != -1) decompose(heavy[u], h, u);
    for (int v : adj[u]) {
        if (v != p && v != heavy[u]) decompose(v, v, u);
    }
}

// 树形DP示例（最大独立集）
void dfs_dp(int u, int p) {
    int take = 1, not_take = 0;
    for (int v : adj[u]) {
        if (v == p) continue;
        dfs_dp(v, u);
        take += dp[v][0]; // 取u时，子节点不能取
        not_take += max(dp[v][0], dp[v][1]); // 不取u时，子节点随意
    }
    dp[u][1] = take;
    dp[u][0] = not_take;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, q;
    cin >> n >> q;

    for (int i = 1; i < n; i++) {
        int u, v;
        cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    // 初始化
    dfs_lca(1, 0);
    dfs_hld(1, 0);
    cur_pos = 0;
    decompose(1, 1, 0);

    // 处理查询
    while (q--) {
        int u, v;
        cin >> u >> v;
        cout << lca(u, v) << '\n';
    }

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5;
vector<int> g[N];
int indeg[N];

// Kahn算法（BFS拓扑排序）
vector<int> topological_sort(int n) {
    vector<int> res;
    queue<int> q;

    // 初始化入度
    for (int i = 1; i <= n; i++) {
        if (indeg[i] == 0) {
            q.push(i);
        }
    }

    while (!q.empty()) {
        int u = q.front();
        q.pop();
        res.push_back(u);

        for (int v : g[u]) {
            indeg[v]--;
            if (indeg[v] == 0) {
                q.push(v);
            }
        }
    }

    // 检查是否有环
    if (res.size() != n) {
        return {}; // 存在环，返回空数组
    }
    return res;
}

// DFS拓扑排序（检测环）
bool dfs(int u, vector<int>& color, vector<int>& order) {
    color[u] = 1; // 正在访问

    for (int v : g[u]) {
        if (color[v] == 1) return false; // 发现环
        if (color[v] == 0 && !dfs(v, color, order)) return false;
    }

    color[u] = 2; // 访问完成
    order.push_back(u);
    return true;
}

bool topological_sort_dfs(int n) {
    vector<int> color(n + 1, 0); // 0=未访问，1=访问中，2=已访问
    vector<int> order;

    for (int i = 1; i <= n; i++) {
        if (color[i] == 0 && !dfs(i, color, order)) {
            return false; // 有环
        }
    }

    reverse(order.begin(), order.end());
    // order即为拓扑序
    return true;
}

int main() {
    int n, m;
    cin >> n >> m;

    // 读入有向边
    for (int i = 0; i < m; i++) {
        int u, v;
        cin >> u >> v;
        g[u].push_back(v);
        indeg[v]++;
    }

    // 方法1：Kahn算法
    vector<int> topo = topological_sort(n);
    if (topo.empty()) {
        cout << "有环！" << endl;
    } else {
        for (int x : topo) cout << x << " ";
        cout << endl;
    }

    // 方法2：DFS检测环
    if (!topological_sort_dfs(n)) {
        cout << "有环！" << endl;
    }

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

struct Edge {
    int to, rev;
    long long cap;
    Edge(int to, int rev, long long cap) : to(to), rev(rev), cap(cap) {}
};

class Dinic {
    int n;
    vector<vector<Edge>> g;
    vector<int> level, iter;

    void bfs(int s) {
        level.assign(n, -1);
        queue<int> q;
        level[s] = 0;
        q.push(s);
        while (!q.empty()) {
            int v = q.front(); q.pop();
            for (auto &e : g[v]) {
                if (e.cap > 0 && level[e.to] < 0) {
                    level[e.to] = level[v] + 1;
                    q.push(e.to);
                }
            }
        }
    }

    long long dfs(int v, int t, long long f) {
        if (v == t) return f;
        for (int &i = iter[v]; i < (int)g[v].size(); i++) {
            Edge &e = g[v][i];
            if (e.cap > 0 && level[v] < level[e.to]) {
                long long d = dfs(e.to, t, min(f, e.cap));
                if (d > 0) {
                    e.cap -= d;
                    g[e.to][e.rev].cap += d;
                    return d;
                }
            }
        }
        return 0;
    }

public:
    Dinic(int n) : n(n), g(n) {}

    void add_edge(int from, int to, long long cap) {
        g[from].emplace_back(to, g[to].size(), cap);
        g[to].emplace_back(from, g[from].size() - 1, 0);
    }

    long long max_flow(int s, int t) {
        long long flow = 0;
        while (true) {
            bfs(s);
            if (level[t] < 0) return flow;
            iter.assign(n, 0);
            long long f;
            while ((f = dfs(s, t, 1e18)) > 0) {
                flow += f;
            }
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    // 示例：读取n个点，m条边，源点s，汇点t
    int n, m, s, t;
    cin >> n >> m >> s >> t;
    s--; t--;

    Dinic dinic(n);
    for (int i = 0; i < m; i++) {
        int u, v, c;
        cin >> u >> v >> c;
        u--; v--;
        dinic.add_edge(u, v, c);
    }

    cout << dinic.max_flow(s, t) << '\n';
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// DFS 递归模板
void dfs(int u, vector<vector<int>>& graph, vector<bool>& visited) {
    visited[u] = true;
    // 处理当前节点
    for (int v : graph[u]) {
        if (!visited[v]) {
            dfs(v, graph, visited);
        }
    }
}

// DFS 栈实现（非递归）
void dfs_stack(int start, vector<vector<int>>& graph) {
    vector<bool> visited(graph.size(), false);
    stack<int> stk;
    stk.push(start);
    visited[start] = true;

    while (!stk.empty()) {
        int u = stk.top();
        stk.pop();
        // 处理节点 u
        for (int v : graph[u]) {
            if (!visited[v]) {
                visited[v] = true;
                stk.push(v);
            }
        }
    }
}

// BFS 队列实现
void bfs(int start, vector<vector<int>>& graph) {
    int n = graph.size();
    vector<bool> visited(n, false);
    queue<int> q;
    q.push(start);
    visited[start] = true;

    while (!q.empty()) {
        int u = q.front();
        q.pop();
        // 处理节点 u
        for (int v : graph[u]) {
            if (!visited[v]) {
                visited[v] = true;
                q.push(v);
            }
        }
    }
}

// Flood Fill 示例（网格DFS）
int dx[4] = {1, -1, 0, 0};
int dy[4] = {0, 0, 1, -1};

void floodFill(int x, int y, vector<vector<char>>& grid, vector<vector<bool>>& visited) {
    int n = grid.size(), m = grid[0].size();
    visited[x][y] = true;

    for (int i = 0; i < 4; i++) {
        int nx = x + dx[i], ny = y + dy[i];
        if (nx >= 0 && nx < n && ny >= 0 && ny < m && 
            !visited[nx][ny] && grid[nx][ny] == '.') {
            floodFill(nx, ny, grid, visited);
        }
    }
}

